import { customElement, property } from '@umbraco-cms/backoffice/external/lit';
import { UMB_UFM_RENDER_CONTEXT, UmbUfmElementBase } from '@umbraco-cms/backoffice/ufm';
import { FormsFormItemRepository } from '../../section/forms/repository';

const elementName = 'ufm-form-name';

@customElement(elementName)
export class FormsUfmFormNameElement extends UmbUfmElementBase {
  @property()
  alias?: string;

  constructor() {
    super();

    this.consumeContext(UMB_UFM_RENDER_CONTEXT, (context) => {
      this.observe(
        context.value,
        async (value) => {
          const formId = this.#getFormIdFromValue(value);
          if (formId) {
            const repository = new FormsFormItemRepository(this);
            const { data } = await repository.requestItems([formId]);
            if (data && data.length > 0) {
              this.value = data[0].name;
            }
          }
        },
        'observeValue',
      );
    });
  }

  #getFormIdFromValue(value) : string | undefined {
    if (this.alias && typeof value === 'object') {
      const valueAsObject = value as object;

      // Handle both the single form picker (where we have just a form Id) and
      // the form details picker (where we have an object, with a `formId` property containing the form Id).
      const formDetails = valueAsObject[this.alias];
      if (!formDetails) {
        return undefined;
      }

      if (typeof formDetails === 'object') {
        return formDetails["formId"].toString();
      }
      else {
        return formDetails.toString();
      }
    }
  }
}

export { FormsUfmFormNameElement as element };

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsUfmFormNameElement;
  }
}