import { FormBuildermToken, UmbUfmComponentBase } from '@umbraco-cms/backoffice/ufm';
import './form-name.element.js';

export class FormsUfmFormNameComponent extends UmbUfmComponentBase {
  render(token: FormBuildermToken) {
    if (!token.text) return;

    const attributes = super.getAttributes(token.text);
    return `<ufm-form-name ${attributes}></ufm-form-name>`;
  }
}

export { FormsUfmFormNameComponent as api };